#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class DataController : ControllerBase
    {
        private readonly global::IDataService iDataService;
        public DataController(global::IDataService iDataService)
        {
            this.iDataService = iDataService;
        }
        [Route("CreateUser/{name}")]
        [HttpPost]
        public string CreateUser([FromRoute] string name)
        {
            return this.iDataService.CreateUser(name);
        }
        [Route("GetUser/{id}")]
        [HttpGet]
        public string GetUser([FromRoute] string id)
        {
            return this.iDataService.GetUser(id);
        }
    }
}
